   339→// buildSharedPVC 构建 namespace 级共享 PersistentVolumeClaim
   340→// 通过 spec.volumeName 显式绑定到集群共享 PV
   341→func buildSharedPVC(namespace, pvcName, pvName string, readOnly bool) *corev1.PersistentVolumeClaim {
   342→	accessMode := corev1.ReadWriteMany
   343→	if readOnly {
   344→		accessMode = corev1.ReadOnlyMany
   345→	}
   346→
   347→	storageClass := ""
   348→	return &corev1.PersistentVolumeClaim{
   349→		ObjectMeta: metav1.ObjectMeta{
   350→			Name:      pvcName,
   351→			Namespace: namespace,
   352→		},
   353→		Spec: corev1.PersistentVolumeClaimSpec{
   354→			VolumeName:       pvName,
   355→			AccessModes:      []corev1.PersistentVolumeAccessMode{accessMode},
   356→			StorageClassName: &storageClass,
   357→			Resources: corev1.VolumeResourceRequirements{
   358→				Requests: corev1.ResourceList{
   359→					corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
   360→				},
   361→			},
   362→		},
   363→	}
   364→}
